-- =========================================================================
-- ADM metadata dictionary bootstrap script.
-- This file creates the adm_metadata table and loads the metadata catalog used
-- to describe the ADM model structure, source tables, and relationship rules.
-- Each row is a metadata record, not business data from the model itself.
-- The table stores three record types in metadata_object_type: entity,
-- relationship, and attribute.
-- Entity rows define a modeled table or concept such as BUSINESS_DOMAINS.
-- Attribute rows describe columns that belong to an entity or relationship.
-- Relationship rows describe bridge tables that connect two ADM entities.
-- metadata_code is the main identifier and follows a hierarchical pattern.
-- Entity format: ENTITY.<ENTITY_NAME>.
-- Attribute format: ATTRIBUTE.<ENTITY_NAME>.<ATTRIBUTE_NAME>.
-- Relationship format: RELATIONSHIP.<RELATIONSHIP_NAME>.
-- metadata_parent_code links an attribute back to its owning entity or
-- relationship so the catalog can be traversed consistently.
-- =========================================================================

CREATE EXTENSION IF NOT EXISTS pgcrypto;

CREATE TABLE IF NOT EXISTS adm_metadata (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    metadata_code VARCHAR(160) NOT NULL,
    metadata_name VARCHAR(200) NOT NULL,
    metadata_object_type VARCHAR(20) NOT NULL,
    metadata_parent_code VARCHAR(160) NULL,
    metadata_source_table_name VARCHAR(150) NOT NULL,
    metadata_source_column_name VARCHAR(150) NULL,
    metadata_related_from_code VARCHAR(160) NULL,
    metadata_related_to_code VARCHAR(160) NULL,
    metadata_relationship_type_column_name VARCHAR(150) NULL,
    metadata_business_definition TEXT NOT NULL,
    metadata_model_purpose TEXT NOT NULL,
    metadata_usage_guidance TEXT NOT NULL,
    metadata_example_values TEXT NULL,
    metadata_cardinality_description VARCHAR(120) NULL,
    metadata_status VARCHAR(30) NOT NULL DEFAULT 'active',
    created_at TIMESTAMP NOT NULL DEFAULT now(),
    updated_at TIMESTAMP NOT NULL DEFAULT now(),

    CONSTRAINT uq_adm_metadata_code
        UNIQUE (metadata_code),

    CONSTRAINT chk_adm_metadata_object_type
        CHECK (metadata_object_type IN ('entity', 'relationship', 'attribute')),

    CONSTRAINT chk_adm_metadata_status
        CHECK (metadata_status IN ('active', 'deprecated', 'retired'))
);

INSERT INTO adm_metadata (
    metadata_code,
    metadata_name,
    metadata_object_type,
    metadata_parent_code,
    metadata_source_table_name,
    metadata_source_column_name,
    metadata_related_from_code,
    metadata_related_to_code,
    metadata_relationship_type_column_name,
    metadata_business_definition,
    metadata_model_purpose,
    metadata_usage_guidance,
    metadata_example_values,
    metadata_cardinality_description,
    metadata_status
)
VALUES
    ('ENTITY.BUSINESS_DOMAINS', 'Business Domains', 'entity', NULL, 'business_domains', NULL, NULL, NULL, NULL, 'Defines the business domain records used as a core model level for grouping capabilities, processes, systems, data entities, and technology impact.', 'Provides the highest-level business context for ADM analysis, ownership, capability mapping, system mapping, and impact assessment.', 'Create one row per major business domain. Use domains to organize architecture views and to trace from business areas to capabilities, processes, applications, data, and technologies.', 'Claims, Underwriting, Policy Administration, Billing and Payments, Customer Service', 'One metadata row describes one modeled ADM entity/table.', 'active'),
